// Filtrar leads que precisam de follow-up
const leads = $input.item.json;
const agora = new Date();
const HORAS_48 = 48 * 60 * 60 * 1000;
const MAX_TENTATIVAS = 3;

const statusValidos = ['novo', 'contatado', 'interessado'];

const leadsFiltrados = leads.filter(lead => {
  // Só leads com status válido
  if (!statusValidos.includes(lead.status_crm)) return false;

  // Só leads com telefone
  if (!lead.phone) return false;

  // Verifica tentativas de follow-up
  const followUps = (lead.follow_ups || []).filter(f => f.nota && f.nota.includes('Follow-up'));
  if (followUps.length >= MAX_TENTATIVAS) return false;

  // Verifica se já passou 48h desde última atualização
  const ultimaAtualizacao = new Date(lead.updatedAt || lead.createdAt);
  const diff = agora - ultimaAtualizacao;
  if (diff < HORAS_48) return false;

  return true;
});

console.log(`Leads para follow-up: ${leadsFiltrados.length}`);
return leadsFiltrados.map(lead => ({ json: lead }));

// Montar mensagem de follow-up baseada no número de tentativas
const lead = $input.item.json;
const followUps = (lead.follow_ups || []).filter(f => f.nota && f.nota.includes('Follow-up'));
const tentativa = followUps.length + 1;

let mensagem = '';
const nome = lead.nome_contato || 'tudo bem';
const empresa = lead.nome_empresa ? ` da *${lead.nome_empresa}*` : '';

if (tentativa === 1) {
  mensagem = `Olá! 👷 Aqui é a *LIS* da *Giltec Locações* novamente.\n\nPassei para saber se ${nome}${empresa} ainda tem interesse em nossos equipamentos para construção civil.\n\nPosso te ajudar com alguma coisa? 😊`;
} else if (tentativa === 2) {
  mensagem = `Oi! 🏗️ LIS da Giltec aqui.\n\nSei que você está ocupado(a), mas queria deixar nosso site para você dar uma olhada nos equipamentos disponíveis:\n👉 https://gilteclocacoes.com.br\n\nQualquer dúvida é só chamar! 😊`;
} else if (tentativa === 3) {
  mensagem = `Olá! 👷 Última mensagem da LIS, Giltec Locações.\n\nSe precisar de equipamentos para sua obra no RJ, estamos à disposição! Temos mais de 30 tipos de equipamentos disponíveis.\n\nAté mais e sucesso na obra! 🏗️`;
}

return [{ json: { ...lead, mensagem, tentativa } }];
